[data-tooltip] {
  position: relative;
  cursor: help;
}

[data-tooltip]::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%) translateY(4px);
  background: #333;
  color: white;
  padding: 6px 12px;
  border-radius: 6px;
  font-size: 0.85rem;
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s, transform 0.2s;
}

[data-tooltip]:hover::after {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}
/* <span data-tooltip='Hello world'>Hover me</span> */

.dashboard {
  display: grid;
  grid-template-areas:
    'sidebar header header'
    'sidebar main   aside'
    'sidebar footer footer';
  grid-template-columns: 250px 1fr 300px;
  grid-template-rows: 60px 1fr 40px;
  min-height: 100vh;
  gap: 1px;
}

.header { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main { grid-area: main; overflow-y: auto; }
.aside { grid-area: aside; }
.footer { grid-area: footer; }

@media (max-width: 768px) {
  .dashboard {
    grid-template-areas: 'header' 'main' 'aside' 'footer';
    grid-template-columns: 1fr;
    grid-template-rows: 60px 1fr auto 40px;
  }
  .sidebar { display: none; }
}

.comparison {
  position: relative;
  overflow: hidden;
  width: 600px;
  aspect-ratio: 16/9;
}

.comparison img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.comparison .after {
  clip-path: inset(0 0 0 var(--pos, 50%));
}

.comparison input[type='range'] {
  position: absolute;
  width: 100%;
  height: 100%;
  opacity: 0;
  cursor: ew-resize;
  z-index: 2;
}
/* JS: input.oninput = e => el.style.setProperty('--pos', e.target.value + '%') */

.flip-card {
  perspective: 1000px;
  width: 300px;
  height: 200px;
}

.flip-card-inner {
  width: 100%;
  height: 100%;
  position: relative;
  transition: transform 0.6s;
  transform-style: preserve-3d;
}

.flip-card:hover .flip-card-inner {
  transform: rotateY(180deg);
}

.flip-card-front, .flip-card-back {
  position: absolute;
  width: 100%;
  height: 100%;
  backface-visibility: hidden;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.flip-card-front { background: #2196F3; color: white; }
.flip-card-back { background: #4CAF50; color: white; transform: rotateY(180deg); }

:root {
  --step--2: clamp(0.69rem, 0.66rem + 0.18vw, 0.80rem);
  --step--1: clamp(0.83rem, 0.78rem + 0.29vw, 1.00rem);
  --step-0: clamp(1.00rem, 0.91rem + 0.43vw, 1.25rem);
  --step-1: clamp(1.20rem, 1.07rem + 0.63vw, 1.56rem);
  --step-2: clamp(1.44rem, 1.26rem + 0.89vw, 1.95rem);
  --step-3: clamp(1.73rem, 1.48rem + 1.24vw, 2.44rem);
  --step-4: clamp(2.07rem, 1.73rem + 1.70vw, 3.05rem);
}

body { font-size: var(--step-0); line-height: 1.6; }
h1 { font-size: var(--step-4); }
h2 { font-size: var(--step-3); }
h3 { font-size: var(--step-2); }
small { font-size: var(--step--1); }
